import { clsx, type ClassValue } from "clsx";
import { twMerge } from "tailwind-merge";

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs));
}

export function formatWhatsAppLink(message: string): string {
  const phone = SITE_CONFIG.whatsapp.replace(/\D/g, "");
  const encoded = encodeURIComponent(message);
  return `https://wa.me/${phone}?text=${encoded}`;
}

import { SITE_CONFIG } from "./constants";

import type { Metadata } from "next";
import { SITE_CONFIG } from "./constants";

interface PageSEO {
  title: string;
  description: string;
  keywords: string[];
  path: string;
  ogImage?: string;
}

export function generatePageMetadata({
  title,
  description,
  keywords,
  path,
  ogImage = SITE_CONFIG.ogImage,
}: PageSEO): Metadata {
  const fullTitle =
    path === "/"
      ? `${SITE_CONFIG.name} | ${SITE_CONFIG.tagline}`
      : `${title} | ${SITE_CONFIG.name}`;

  const url = `${SITE_CONFIG.url}${path}`;

  return {
    title: fullTitle,
    description,
    keywords: keywords.join(", "),
    authors: [{ name: SITE_CONFIG.name }],
    creator: SITE_CONFIG.name,
    metadataBase: new URL(SITE_CONFIG.url),
    alternates: {
      canonical: url,
    },
    openGraph: {
      type: "website",
      locale: "en_IN",
      url,
      siteName: SITE_CONFIG.name,
      title: fullTitle,
      description,
      images: [
        {
          url: ogImage,
          width: 1200,
          height: 630,
          alt: `${SITE_CONFIG.name} - Home Improvement Services in Surat`,
        },
      ],
    },
    twitter: {
      card: "summary_large_image",
      title: fullTitle,
      description,
      images: [ogImage],
    },
    robots: {
      index: true,
      follow: true,
      googleBot: {
        index: true,
        follow: true,
        "max-video-preview": -1,
        "max-image-preview": "large",
        "max-snippet": -1,
      },
    },
  };
}

export function generateServiceMetadata(
  serviceName: string,
  description: string,
  slug: string,
  keywords: string[]
): Metadata {
  return generatePageMetadata({
    title: `${serviceName} Services in Surat`,
    description,
    keywords: [
      ...keywords,
      `${serviceName} Surat`,
      `${serviceName} services Gujarat`,
      "home improvement Surat",
      SITE_CONFIG.name,
    ],
    path: `/services/${slug}`,
  });
}

